-- ============================================
-- Legislacao full-site: pedro-cunha-lima / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 1978-1982
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/1757/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = pedro-cunha-lima-senado-completo-autoria-substantiva-1978-1982-20260506
--   coverage_scope = inventario_completo_senado_autoria_substantiva_1978_1982_20260506
--
-- Filtro factual: endpoint senador/1757/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=1757
--   com NumOrdemAutor=1. Resultado deste snapshot: 33 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration insere rows ausentes e atualiza coverage/metadata somente em
-- rows alvo Senado sem coverage_id divergente.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'pedro-cunha-lima';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'pedro-cunha-lima: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'pedro-cunha-lima-senado-completo-autoria-substantiva-1978-1982-20260506';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('25849', '27035', '27617', '28293', '26254', '31129', '31156', '31192', '23802', '26786', '27163', '27448', '27689', '27808', '27985', '28273', '28342', '28456', '28562', '28732', '28796', '28852', '28933', '28973', '29030', '29129', '29478', '30174', '31068', '31220', '31342', '29763', '29779');

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('25849', '27035', '27617', '28293', '26254', '31129', '31156', '31192', '23802', '26786', '27163', '27448', '27689', '27808', '27985', '28273', '28342', '28456', '28562', '28732', '28796', '28852', '28933', '28973', '29030', '29129', '29478', '30174', '31068', '31220', '31342', '29763', '29779')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'pedro-cunha-lima-senado-completo-autoria-substantiva-1978-1982-20260506';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao pedro-cunha-lima: % rows alvo Senado ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'PB'
    AND COALESCE(hp.periodo_inicio, 9999) <= 1982
    AND COALESCE(hp.periodo_fim, 9999) >= 1978;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao pedro-cunha-lima: mandato Senado/PB 1978-1982 nao encontrado em historico_politico';
  END IF;
END $$;

